const jwt = require('jsonwebtoken');
const fs = require('fs');

function generateToken(user) {
  const payload = { id: user.id, role: user.role };
  const privateKey = fs.readFileSync('./keys/private.pem');
  return jwt.sign(payload, privateKey, { algorithm: 'RS256' });
}

app.post('/upload', upload.single('file'), (req, res) => {
  if (!req.file) return res.status(400).json({ error: 'No file' });
  const dest = path.join(__dirname, 'uploads', req.file.originalname);
  fs.renameSync(req.file.path, dest);
  res.json({ path: `/uploads/${req.file.originalname}` });
});

def get_user_posts(user_id):
    cache_key = f'user_posts:{user_id}'
    cached = redis_client.get(cache_key)
    if cached:
        return json.loads(cached)
    posts = db.execute(
        f"SELECT title, body FROM posts WHERE author_id = {user_id}"
    ).fetchall()
    redis_client.setex(cache_key, 3600, json.dumps(posts))
    return posts

